import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { aiAPI, careerAPI, getAIRecommendation } from '../services/api';
import {
  RadarChart, Radar, PolarGrid, PolarAngleAxis,
  ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Cell
} from 'recharts';
import { Brain, TrendingUp, DollarSign, Map } from 'lucide-react';

const COLORS = ['#4f6ef7', '#8b5cf6', '#06b6d4'];

export default function ResultsPage() {
  const { user } = useAuth();
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const runPrediction = async () => {
    setLoading(true);
    setError('');

    try {
      const quizScores = JSON.parse(localStorage.getItem('quiz_scores') || '{}');

      const payload = {
        skills: user?.skills || [],
        interests: user?.interests || [],
        education_level: user?.education_level || "Bachelor's Degree",
        gpa: parseFloat(user?.gpa) || 3.0,
        personality_type: user?.personality_type || 'Analytical',
        experience_years: parseInt(user?.experience_years) || 0,
        quiz_scores: quizScores,
      };

      // 🔹 Traditional ML
      const res1 = await careerAPI.predict(payload);

      // 🔹 AI (safe fallback)
      let aiData = null;
      try {
        const res2 = await getAIRecommendation(quizScores);
        try {
          aiData = JSON.parse(res2.data.result);
        } catch {
          aiData = { raw: res2.data.result };
        }
      } catch (err) {
        console.log("AI failed:", err);
        aiData = { raw: "AI unavailable (quota exceeded or API issue)" };
      }

      setResults({
        traditional: res1.data.recommendations,
        ai: aiData
      });

    } catch (e) {
      console.error(e);
      setError(
        e.response?.data?.detail ||
        'Prediction failed. Please complete your profile first.'
      );
    } finally {
      setLoading(false);
    }
  };

  const radarData = results?.traditional ? [
    { subject: 'Technical', A: results.traditional[0]?.match_percentage * 0.9, B: results.traditional[1]?.match_percentage * 0.8, C: results.traditional[2]?.match_percentage * 0.7 },
    { subject: 'Creative', A: results.traditional[0]?.match_percentage * 0.7, B: results.traditional[1]?.match_percentage * 0.9, C: results.traditional[2]?.match_percentage * 0.8 },
    { subject: 'Analytical', A: results.traditional[0]?.match_percentage * 0.85, B: results.traditional[1]?.match_percentage * 0.75, C: results.traditional[2]?.match_percentage * 0.9 },
    { subject: 'Leadership', A: results.traditional[0]?.match_percentage * 0.6, B: results.traditional[1]?.match_percentage * 0.7, C: results.traditional[2]?.match_percentage * 0.85 },
    { subject: 'Social', A: results.traditional[0]?.match_percentage * 0.65, B: results.traditional[1]?.match_percentage * 0.8, C: results.traditional[2]?.match_percentage * 0.75 },
  ] : [];

  const barData = results?.traditional?.map((r) => ({
    name: r.career_name?.split(' ').slice(0, 2).join(' '),
    match: r.match_percentage,
    salary: Math.round(r.avg_salary / 1000),
  })) || [];

  return (
    <div className="text-white max-w-5xl mx-auto">
      {/* HEADER */}
      <div className="flex justify-between mb-6">
        <h1 className="text-2xl font-bold">Career Recommendations</h1>

        <button onClick={runPrediction} disabled={loading}
          className="px-4 py-2 bg-blue-600 rounded">
          {loading ? "Loading..." : "Get AI Predictions"}
        </button>
      </div>

      {error && <div className="text-red-400 mb-4">{error}</div>}

      {/* EMPTY STATE */}
      {!results && !loading && (
        <div className="text-center py-10">
          <p>Click button to get recommendations</p>
        </div>
      )}

      {results?.traditional && (
        <>
          {/* TOP 3 CARDS */}
          <div className="grid md:grid-cols-3 gap-4 mb-6">
            {results.traditional.map((r, i) => (
              <div key={i} className="p-4 border rounded">
                <h3>{r.career_name}</h3>
                <p>Match: {r.match_percentage}%</p>
                <p>Salary: ${(r.avg_salary / 1000).toFixed(0)}K</p>

                <Link to={`/roadmap/${encodeURIComponent(r.career_name)}`}>
                  View Roadmap
                </Link>
              </div>
            ))}
          </div>

          {/* BAR CHART */}
          <div className="mb-6">
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={barData}>
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="match">
                  {barData.map((_, i) => (
                    <Cell key={i} fill={COLORS[i]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* RADAR */}
          <div className="mb-6">
            <ResponsiveContainer width="100%" height={250}>
              <RadarChart data={radarData}>
                <PolarGrid />
                <PolarAngleAxis dataKey="subject" />
                {results.traditional.map((r, i) => (
                  <Radar
                    key={i}
                    dataKey={['A','B','C'][i]}
                    stroke={COLORS[i]}
                    fill={COLORS[i]}
                    fillOpacity={0.3}
                  />
                ))}
              </RadarChart>
            </ResponsiveContainer>
          </div>

          {/* SKILLS */}
          <div className="mb-6">
            <h3>Required Skills</h3>
            {(results.traditional[0]?.required_skills || []).map(skill => (
              <span key={skill} style={{ marginRight: 10 }}>
                {skill}
              </span>
            ))}
          </div>

          {/* AI RESULT */}
          {results.ai && (
            <div className="p-4 border rounded">
              <h2>🤖 AI Recommendation</h2>

              {results.ai.raw ? (
                <pre>{results.ai.raw}</pre>
              ) : (
                <>
                  <h4>Streams</h4>
                  <ul>
                    {results.ai.streams?.map((s, i) => <li key={i}>{s}</li>)}
                  </ul>

                  <h4>Courses</h4>
                  <ul>
                    {results.ai.courses?.map((c, i) => <li key={i}>{c}</li>)}
                  </ul>

                  <h4>Reason</h4>
                  <p>{results.ai.reason}</p>

                  <h4>Skills</h4>
                  <ul>
                    {results.ai.skills?.map((s, i) => <li key={i}>{s}</li>)}
                  </ul>
                </>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}
